        private static Asset Build(
            string id,
            Guid categoryId,
            Guid locationId,
            string name,
            string assetCode,
            string specification,
            AssetState state,
            DateTime createdDate,
            DateTime installedDate)
        {
            return new Asset
            {
                Id = Guid.Parse(id),
                CategoryId = categoryId,
                LocationId = locationId,
                Name = name,
                AssetCode = assetCode,
                Specification = specification,
                State = state,
                CreatedAtUtc = createdDate,
                InstalledAtUtc = installedDate,
            };
        }
    }

